// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract SafeCaller {
 // Proper pattern: always check return value
 function callTarget(address target, bytes calldata data) public payable {
 // .call() returns (bool success, bytes memory returnData)
 (bool success, bytes memory returnData) = target.call{value: msg.value, gas: 5000}(data);

 // MUST check success - silent failures are dangerous
 require(success, "Call to target failed");

 // Optional: decode return data if needed
 // uint256 result = abi.decode(returnData, (uint256));
 }

 // Example: safe transfer pattern
 function safeTransfer(address token, address to, uint256 amount) internal {
 // Using low-level call for token transfer
 bytes memory data = abi.encodeWithSignature("transfer(address,uint256)", to, amount);
 (bool success, ) = token.call(data);
 require(success, "Transfer failed");
 }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

// Proxy Contract
contract Proxy {
 address public implementation; // slot 0
 address public admin; // slot 1

 constructor(address _implementation) {
 implementation = _implementation;
 admin = msg.sender;
 }

 // Fallback uses delegatecall to forward execution
 fallback() external payable {
 // Execute implementation code in THIS contract's storage
 (bool success, ) = implementation.delegatecall(msg.data);
 require(success, "Delegatecall failed");
 }

 // Upgrade function - only admin can change implementation
 function upgrade(address newImplementation) external {
 require(msg.sender == admin, "Only admin");
 implementation = newImplementation;
 }
}

// Implementation Contract (Logic)
contract V1 {
 uint256 public value;

 function setValue(uint256 _value) external {
 value = _value;
 }
}

// Upgraded Implementation
contract V2 {
 uint256 public value;
 uint256 public lastUpdated;

 function setValue(uint256 _value) external {
 value = _value;
 lastUpdated = block.timestamp;
 }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract SecureVault {
 mapping(address => uint256) public balances;

 // WRONG - Vulnerable to reentrancy
 function withdrawBad() external {
 uint256 amount = balances[msg.sender];
 require(amount > 0, "No balance");

 // VULNERABLE: External call BEFORE state update
 (bool success, ) = msg.sender.call{value: amount}("");
 require(success, "Transfer failed");

 // State update happens AFTER external call - TOO LATE!
 balances[msg.sender] = 0;
 }

 // CORRECT - CEI Pattern
 function withdrawCorrect() external {
 uint256 amount = balances[msg.sender];
 require(amount > 0, "No balance");

 // 1. CHECKS - Validate conditions
 // (done above with require)

 // 2. EFFECTS - Update state FIRST
 balances[msg.sender] = 0;

 // 3. INTERACTIONS - External call LAST
 (bool success, ) = msg.sender.call{value: amount}("");
 require(success, "Transfer failed");
 }

 // BEST PRACTICE - Use ReentrancyGuard
 bool private locked;

 function withdrawWithGuard() external {
 require(!locked, "No reentrancy");
 locked = true;

 uint256 amount = balances[msg.sender];
 require(amount > 0, "No balance");

 balances[msg.sender] = 0;

 (bool success, ) = msg.sender.call{value: amount}("");
 require(success, "Transfer failed");

 locked = false;
 }

 receive() external payable {
 balances[msg.sender] += msg.value;
 }
}
